/// <summary>
///
/// </summary>
static ETGRailCarLoadingLineTable find(ETGRailLoadingSerialNumber   railLoadingSerialNumber,
                             LineNum   _lineNum     = 0,
                             boolean   _update      = false)
{
    ETGRailCarLoadingLineTable railCarLoadingLineTable;

    if (railLoadingSerialNumber)
    {
        if (_update)
        {
            railCarLoadingLineTable.selectForUpdate(_update);
        }
        if (_lineNum)
        {
            select firstonly railCarLoadingLineTable
                index hint RailLoadingLineTableIdx
                where railCarLoadingLineTable.ETGRailLoadingSerialNumber  == railLoadingSerialNumber
                &&    railCarLoadingLineTable.LineNum  == _lineNum;
        }
        else
        {
            select firstonly railCarLoadingLineTable
                index hint RailLoadingLineTableIdx
                where railCarLoadingLineTable.ETGRailLoadingSerialNumber == railLoadingSerialNumber;
        }
    }

    return railCarLoadingLineTable;
}

static boolean  exist(ETGRailLoadingSerialNumber   railLoadingSerialNumber,
                      LineNum   _lineNum = naReal())
{
    if (!railLoadingSerialNumber)
    {
        return false;
    }

    if (_lineNum == naReal())
    {
        return (select firstonly RecId from ETGRailCarLoadingLineTable
                    index hint RailLoadingLineTableIdx
                    where ETGRailCarLoadingLineTable.ETGRailLoadingSerialNumber     == railLoadingSerialNumber).RecId != 0;
    }

    return (select firstonly RecId from ETGRailCarLoadingLineTable
                index hint RailLoadingLineTableIdx
                where ETGRailCarLoadingLineTable.ETGRailLoadingSerialNumber  == railLoadingSerialNumber
                &&     ETGRailCarLoadingLineTable.LineNum == _lineNum).RecId != 0;
}

public InventTable inventTable(
    ItemId  _itemId       = this.ItemId,
    boolean _forUpdate    = false)
{
    return InventTable::find(_itemId, _forUpdate);
}

public InventDim inventDim(boolean  _forUpdate = false)
{
    return InventDim::find(this.InventDimId, _forUpdate);
}

public boolean validateField(FieldId _fieldId)
{
    boolean ret = super(_fieldId);

    if (_fieldId == fieldNum(ETGRailCarLoadingLineTable, ItemId))
    {
        InventTable inventTable;

        select firstOnly crossCompany inventTable
        where inventTable.ItemId == this.ItemId;

        if (!inventTable.RecId)
        {
            error(strFmt("@ETG_New:ETGRailCarLoadingLineTableError", this.ItemId));
            return false;
        }

        return true; // valid cross-company item
    }

    return ret;
}
